{"db_name":"stocktrade_database","query":"WITH tbl AS (
  SELECT table_name
  FROM information_schema.tables
  WHERE table_schema = 'main'
), cap AS (
  SELECT table_name AS Symbol
  FROM tbl
)
SELECT Symbol FROM cap LIMIT 5;"}

