{"db_name":"stocktrade_database","query":"WITH cap_syms AS (
  SELECT Symbol, "Company Description" AS company_name
  FROM stockinfo_database.stockinfo
  WHERE "Market Category"='S' AND ETF='N' AND "Test Issue"='N'
), avail AS (
  SELECT name AS Symbol
  FROM (SELECT * FROM duckdb_tables())
  WHERE schema_name='main'
), syms AS (
  SELECT c.Symbol, c.company_name
  FROM cap_syms c
  JOIN avail a USING (Symbol)
), daily AS (
  SELECT s.Symbol, s.company_name, t.Date, t.High, t.Low
  FROM syms s
  JOIN LATERAL (
    SELECT Date, High, Low FROM main."AGMH" LIMIT 0
  ) t ON TRUE
)
SELECT * FROM syms LIMIT 5;"}

